function definitionsFor(specItem: MissionSpec) {
  const items = specItem.topics.map((topic) => definitionsByTopic[topic]).filter(Boolean);
  if (items.length >= 2) return items;
  return [
    ...items,
    `${specItem.assignmentSubtopic} — подпункт листка, который раскрывает ${specItem.topics.slice(0, 3).join(", ")}.`,
    `${specItem.q.toUpperCase()} связан с эпохой через ${specItem.topics[0]}.`,
  ];
}

