function buildLesson(specItem: MissionSpec) {
  const definitions = definitionsFor(specItem).slice(0, 4).join(" ");
  const subjectBase = subjectOverrides[specItem.id] ?? specItem.core;
  const base = specItem.strictBoss
    ? `${subjectOverrides[specItem.id] ?? fullAnswerLessons[specItem.q]} Дополнительная связка понятий: ${subjectBase} ${definitionsFor(specItem).join(" ")} Внутри этой эпохи каждое понятие раскрывает отдельный слой философской картины: устройство мира, понимание человека, источник знания, нравственный смысл или политический порядок. Поэтому итоговая тема не является перечнем терминов; она показывает, как разные подпункты образуют единую систему взглядов.`
    : subjectBase;
  const distinctions = `Близкое различение: ${specItem.duelCorrect} Ловушка темы: ${specItem.trapCorrection}`;
  const context = `Исторически это относится к разделу ${specItem.sections[0]}: здесь меняется понимание мира, человека и знания внутри соответствующей эпохи.`;
  const manifestation = `В материале листка это проявляется через ${specItem.topics.slice(0, 5).join(", ")}: эти понятия показывают не список слов, а устройство самой философской позиции.`;
  const conclusion = `Мини-вывод: ${specItem.skeleton.join(" ")}`;
  const simpleExplanation = `${definitions} ${base} ${distinctions} ${context} ${manifestation} ${conclusion}`;
  return {
    simpleExplanation,
    textbookCore: `${base} ${definitions}`,
    whyItMatters: `${specItem.assignmentSubtopic} важно потому, что без него нельзя понять ${specItem.topics.slice(0, 3).join(", ")} в контексте эпохи. Понятие связывает мировоззрение, человека и способ объяснения реальности.`,
    keyTerms: specItem.topics,
    blocks: buildLessonBlocks(specItem, definitions, base, distinctions, context, manifestation, conclusion),
  };
}

function buildLessonBlocks(
  specItem: MissionSpec,
  definitions: string,
  base: string,
  distinctions: string,
  context: string,
  manifestation: string,
  conclusion: string,
) {
  const baseBlocks = splitIntoCards(base, "Простыми словами");
  return [
    { title: "Что это?", text: definitions },
    ...baseBlocks,
    { title: "Чем отличается", text: distinctions },
    { title: "Контекст эпохи", text: context },
    { title: "Как это видно в теме", text: manifestation },
    { title: "Мини-вывод", text: conclusion },
  ];
}

function splitIntoCards(text: string, title: string) {
  const sentences = text.match(/[^.!?]+[.!?]+|[^.!?]+$/g)?.map((item) => item.trim()).filter(Boolean) ?? [text];
  const chunks: string[] = [];
  let current = "";
  sentences.forEach((sentence) => {
    const next = current ? `${current} ${sentence}` : sentence;
    if (next.split(/\s+/).length > 95 && current) {
      chunks.push(current);
      current = sentence;
      return;
    }
    current = next;
  });
  if (current) chunks.push(current);
  return chunks.map((chunk, index) => ({ title: chunks.length === 1 ? title : `${title} ${index + 1}`, text: chunk }));
}

